import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.D5wUhsuj.js";const h=JSON.parse('{"title":"Platform Databases","description":"","frontmatter":{},"headers":[],"relativePath":"platform/databases.md","filePath":"platform/databases.md","lastUpdated":1783546178000}'),s={name:"platform/databases.md"};function i(n,e,l,c,d,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="platform-databases" tabindex="-1">Platform Databases <a class="header-anchor" href="#platform-databases" aria-label="Permalink to &quot;Platform Databases&quot;">​</a></h1><p>prokube deployments can include PostgreSQL-based database services for platform components and, depending on the installation, user workloads. Treat database availability and access as deployment-specific unless your administrator has explicitly enabled a self-service database workflow.</p><div class="info custom-block"><p class="custom-block-title">Upstream documentation</p><p>Use the upstream documentation for database and operator reference:</p><ul><li><a href="https://www.postgresql.org/docs/" target="_blank" rel="noreferrer">PostgreSQL documentation</a></li><li><a href="https://access.crunchydata.com/documentation/postgres-operator/latest/" target="_blank" rel="noreferrer">Crunchy Data Postgres Operator documentation</a></li><li><a href="https://docs.timescale.com/" target="_blank" rel="noreferrer">TimescaleDB documentation</a></li></ul></div><h2 id="postgresql" tabindex="-1">PostgreSQL <a class="header-anchor" href="#postgresql" aria-label="Permalink to &quot;PostgreSQL&quot;">​</a></h2><p>PostgreSQL is the default relational database used by several platform components. In prokube deployments that expose database services to users, PostgreSQL instances are usually managed by an operator rather than by manually running database pods.</p><p>Before using PostgreSQL for a workload, confirm with your administrator:</p><ul><li>whether user-managed PostgreSQL instances are available;</li><li>which namespace or workspace owns the database;</li><li>how credentials are created and rotated;</li><li>what backup, restore, and retention policy applies;</li><li>whether network policies or egress profiles restrict database access.</li></ul><p>Do not store database passwords in notebooks, pipeline source code, container images, or shared object-storage buckets. Use Kubernetes Secrets or a platform-provided credential flow.</p><h2 id="timescaledb" tabindex="-1">TimescaleDB <a class="header-anchor" href="#timescaledb" aria-label="Permalink to &quot;TimescaleDB&quot;">​</a></h2><p>Some deployments can provide TimescaleDB for time-series workloads. TimescaleDB availability, version, sizing, and backup policy are deployment-specific. Use it only after the administrator confirms that it is part of the supported platform profile.</p><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><p>Default PostgreSQL settings are not always appropriate for every workload. Query performance depends on schema design, indexes, connection count, memory, storage latency, and database sizing.</p><p>If queries are unexpectedly slow:</p><ul><li>inspect query plans with <code>EXPLAIN</code> or <code>EXPLAIN ANALYZE</code>;</li><li>verify indexes for common filters and joins;</li><li>check connection pooling and long-running transactions;</li><li>confirm the instance has sufficient CPU, memory, and storage throughput;</li><li>ask the database administrator before changing operator-managed database parameters.</li></ul><p>For a starting point, see Crunchy Data&#39;s <a href="https://www.crunchydata.com/blog/optimize-postgresql-server-performance" target="_blank" rel="noreferrer">PostgreSQL performance tuning guidance</a>.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./workspaces.html">Workspaces</a></li><li><a href="./kubernetes.html">Kubernetes Resources</a></li><li><a href="./object_storage.html">Object Storage</a></li><li><a href="./../admin/backup_restore.html">Backup and Restore</a></li></ul>',17)])])}const u=a(s,[["render",i]]);export{h as __pageData,u as default};
